SELECT COUNT(1) FROM BOARD b LEFT JOIN EMP e ON e.EMP_NO = b.REG_EMP_NO WHERE b.DEL_YN = 'N' AND b.BOARD_TYPE_NO = #{boardTypeNo}
AND LOWER(e.EMP_NM) LIKE '%' || LOWER(#{keyword}) || '%'
AND LOWER(b.TITLE) LIKE '%' || LOWER(#{keyword}) || '%'

mapper.update:
